import { useState, useEffect } from "react";
import Sidebar from "./Sidebar";

export default function PaymentSystem() {
  const today = new Date().toISOString().split("T")[0];

  const [showForm, setShowForm] = useState(false);
  const [payments, setPayments] = useState([]);

  const [form, setForm] = useState({
    title: "",
    clientName: "",
    projectName: "",

    paymentType: "ADVANCE",

    totalAmount: "",
    paidAmount: "",
    pendingAmount: "",

    paymentDate: today,
    paymentMethod: "CASH",

    transactionId: "",
    status: "PENDING",

    supplierName: "",
    workerName: "",

    dueDate: "",
    notes: ""
  });

  useEffect(() => {
    fetch("http://localhost:5000/payments")
      .then((res) => res.json())
      .then((data) => setPayments(data));
  }, []);

  const calculatePending = (total, paid) =>
    Number(total || 0) - Number(paid || 0);

  const handleChange = (e) => {
    const { name, value } = e.target;

    let updated = { ...form, [name]: value };

    if (name === "totalAmount" || name === "paidAmount") {
      const total = name === "totalAmount" ? value : form.totalAmount;
      const paid = name === "paidAmount" ? value : form.paidAmount;

      const pending = calculatePending(total, paid);

      updated.pendingAmount = pending;

      if (Number(paid) === 0) updated.status = "PENDING";
      else if (Number(paid) >= Number(total)) updated.status = "PAID";
      else updated.status = "PARTIAL";
    }

    setForm(updated);
  };

  const savePayment = async (e) => {
    e.preventDefault();

    const payload = {
      ...form,
      pendingAmount: calculatePending(form.totalAmount, form.paidAmount)
    };

    const res = await fetch("http://localhost:5000/payments", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload)
    });

    const data = await res.json();

    setPayments([...payments, { ...payload, id: data.id }]);
    setShowForm(false);
  };

  const deletePayment = (index) => {
    setPayments(payments.filter((_, i) => i !== index));
  };

  return (
    <div className="flex bg-gray-100 min-h-screen">
      <Sidebar />

      <div className="flex-1 p-8">

        <div className="flex justify-between mb-6">
          <h1 className="text-2xl font-bold">Payments Management</h1>

          <button
            onClick={() => setShowForm(true)}
            className="bg-blue-600 text-white px-4 py-2 rounded"
          >
            + Add Payment
          </button>
        </div>

        {/* FORM */}
        {showForm && (
          <form
            onSubmit={savePayment}
            className="bg-white p-6 rounded shadow grid grid-cols-2 gap-4 mb-6"
          >

            <input name="title" placeholder="Title" onChange={handleChange} className="border p-2" />
            <input name="clientName" placeholder="Client Name" onChange={handleChange} className="border p-2" />
            <input name="projectName" placeholder="Project Name" onChange={handleChange} className="border p-2" />

            <select name="paymentType" onChange={handleChange} className="border p-2">
              <option value="ADVANCE">Advance</option>
              <option value="FINAL">Final</option>
              <option value="SALARY">Salary</option>
              <option value="MATERIAL">Material</option>
            </select>

            <input name="totalAmount" placeholder="Total Amount" onChange={handleChange} className="border p-2" />
            <input name="paidAmount" placeholder="Paid Amount" onChange={handleChange} className="border p-2" />

            <input name="pendingAmount" value={form.pendingAmount} readOnly className="border p-2 bg-gray-100" />

            <input type="date" name="paymentDate" value={form.paymentDate} onChange={handleChange} className="border p-2" />

            <select name="paymentMethod" onChange={handleChange} className="border p-2">
              <option value="CASH">Cash</option>
              <option value="UPI">UPI</option>
              <option value="BANK">Bank Transfer</option>
              <option value="CHEQUE">Cheque</option>
            </select>

            <input name="transactionId" placeholder="Transaction ID" onChange={handleChange} className="border p-2" />

            <input name="supplierName" placeholder="Supplier Name" onChange={handleChange} className="border p-2" />
            <input name="workerName" placeholder="Worker Name" onChange={handleChange} className="border p-2" />

            <input type="date" name="dueDate" onChange={handleChange} className="border p-2" />

            <textarea name="notes" placeholder="Notes" onChange={handleChange} className="border p-2 col-span-2" />

            <button className="bg-green-600 text-white p-2 rounded">Save</button>

            <button type="button" onClick={() => setShowForm(false)} className="border p-2 rounded">
              Cancel
            </button>
          </form>
        )}

        {/* TABLE */}
        <div className="bg-white rounded shadow">
          <table className="w-full">
            <thead className="bg-gray-200">
              <tr>
                <th>Title</th>
                <th>Total</th>
                <th>Paid</th>
                <th>Pending</th>
                <th>Status</th>
                <th>Action</th>
              </tr>
            </thead>

            <tbody>
              {payments.map((p, i) => (
                <tr key={i} className="text-center border-t">
                  <td>{p.title}</td>
                  <td>{p.totalAmount}</td>
                  <td>{p.paidAmount}</td>
                  <td>{p.pendingAmount}</td>
                  <td>{p.status}</td>
                  <td>
                    <button onClick={() => deletePayment(i)} className="text-red-600">
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>

          </table>
        </div>

      </div>
    </div>
  );
}
